INSERT INTO public.event_types VALUES ('cbd13e4b-e5a9-499d-aaef-f4ff47f66f37', 'd9b37e23-83c3-4203-aff5-2ba4b9918e31', 'DigyGo Slot Booking', 'digygo-slot-booking', 30, 'Digygo enables users to easily book consultation appointments through an integrated calendar, where they can view available time slots, choose a suitable date and time, and confirm their booking instantly; once scheduled, the system automatically blocks the slot to prevent conflicts, sends confirmation notifications, and generates a meeting link, while business owners can manage all appointments from a centralized dashboard to view, reschedule, or track consultation details efficiently.', 'single', 'round-robin', '[]', 'Google Meet', 'days', 30, 'Asia/Kolkata', '{"Fri": {"slots": [{"end": "10:00", "start": "09:30"}, {"end": "11:30", "start": "11:00"}, {"end": "16:30", "start": "16:00"}, {"end": "15:30", "start": "15:00"}], "enabled": true}, "Mon": {"slots": [{"end": "10:00", "start": "09:30"}, {"end": "11:30", "start": "11:00"}, {"end": "16:30", "start": "16:00"}], "enabled": true}, "Sat": {"slots": [], "enabled": false}, "Sun": {"slots": [{"end": "10:00", "start": "09:30"}, {"end": "11:30", "start": "11:00"}, {"end": "16:30", "start": "16:00"}], "enabled": true}, "Thu": {"slots": [{"end": "10:00", "start": "09:30"}, {"end": "11:30", "start": "11:00"}, {"end": "16:30", "start": "16:00"}], "enabled": true}, "Tue": {"slots": [{"end": "09:30", "start": "09:00"}, {"end": "12:30", "start": "12:00"}, {"end": "16:30", "start": "16:00"}], "enabled": true}, "Wed": {"slots": [{"end": "10:00", "start": "09:30"}, {"end": "11:30", "start": "11:00"}, {"end": "16:30", "start": "16:00"}], "enabled": true}}', 0, true, '[{"id": "ff1", "type": "text", "label": "Name", "mapTo": "name", "enabled": true, "required": true, "placeholder": "Your name"}, {"id": "ff2", "type": "email", "label": "Email", "mapTo": "email", "enabled": true, "required": true, "placeholder": "your@email.com"}, {"id": "ff3", "type": "phone", "label